#define IN_RANGE(x, min, max)   ((x) >= (min) && (x) <= (max))
#define MIN(a, b)               ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int iteration,
    __global int *gpuWall,
    __global int *gpuSrc,
    __global int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int *prev,
    __local int *result,
    __global int *outputBuffer)
{
    size_t bx = get_group_id(0);
    size_t tx = get_local_id(0);
    int block_size = (int)get_local_size(0);

    int pyramid_height = border / HALO;
    int smallBlockCol_host = block_size - pyramid_height * HALO * 2;
    if (smallBlockCol_host <= 0) {
        return;
    }
    int blockCols_host = cols / smallBlockCol_host + ((cols % smallBlockCol_host == 0) ? 0 : 1);
    if ((int)bx >= blockCols_host) {
        return;
    }

    int small_block_cols = block_size - iteration * HALO * 2;

    int blkX = small_block_cols * (int)bx - border;
    int blkXmax = blkX + block_size - 1;

    int xidx = blkX + (int)tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? block_size - 1 - (blkXmax - cols + 1) : block_size - 1;

    int W = (int)tx - 1;
    int E = (int)tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    int isValid = IN_RANGE((int)tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;
        if (IN_RANGE((int)tx, i + 1, block_size - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1) {
            break;
        }

        if (computed) {
            prev[tx] = result[tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result[tx];
    }

    (void)rows;
    (void)outputBuffer;
}
